tests.code:
const testData1 = [true, true, false];
const expectedResult = [true,true];
assert.deepEqual(filter(testData1, Boolean), expectedResult);

const testData2 = [{ 'user': 'barney', 'active': true },{ 'user': 'fred', 'active': false } ];
const expectedResult = [{ 'user': 'barney', 'active': true }];
assert.deepEqual(filter(testData2, ({ active }) => active), expectedResult);

// Return true
assert.isBoolean(isObject({}));
// return false
assert.isBoolean(isObject(null));

let arr = new BigUint64Array();
arr[0] = BigInt(0);
arr[1] = BigInt(2);
arr[2] = BigInt(Number.MAX_SAFE_INTEGER);
assert.isTrue(isTypedArray(arr));

const originalArr = [1, 2, 3, 4];
const desiredArr = [2, 3, 4, 5];
const returnVal = map(originalArr, plusOne);
assert.deepEqual(returnVal, desiredArr);

const originalArr = [0, 2, 4, 6];
const desiredArr = [0, 1, 2, 3];
const returnVal = map(originalArr, divideByTwo);
assert.deepEqual(returnVal, desiredArr);

const originalArr = [0, -1, -2];
const desiredArr = [0, 0, 0];
const returnVal = map(originalArr, add);
assert.deepEqual(returnVal, desiredArr);

const mem = memoize(value => value);
const memoizedObj = mem(obj);
assert.deepEqual(obj, memoizedObj);
obj.a = 3;
const memoizedObjNew = mem(obj);
assert.deepEqual(memoizedObj, memoizedObjNew);

const expectedArr = [3, 4];
assert.deepEqual(slice(arr, 2), expectedArr);
assert.deepEqual(origArr, arr);

const s = "I like turtles ! &";
const desiredArr = ["I", "like", "turtles"];
const returnVal = words(s);
assert.deepEqual(returnVal, desiredArr);

const s = "I like turtles";
const desiredArr = ["I", "like", "turtles"];
const returnVal = words(s);
assert.deepEqual(returnVal, desiredArr);

const s = "I like & love turtles !";
const desiredArr = ["I", "like", "&", "love", "turtles"];
const regExp = new RegExp(/&/);
const returnVal = words(s, regExp);
assert.deepEqual(returnVal, desiredArr);

const s = "I like & love turtles \"!\"";
const desiredArr = ["I", "like", "&", "love", "turtles"];
const regExp = new RegExp("/&/");
const returnVal = words(s, regExp);
assert.deepEqual(returnVal, desiredArr);
